// In run_agent_apply() - CRITICAL: Must filter before any action
fn run_agent_apply(global: &GlobalOpts, args: &AgentApplyArgs) -> ExitCode {
    // ... load session, plan, etc ...

    // Load policy and create filter
    let policy = load_policy(global)?;
    let protected_filter = ProtectedFilter::from_guardrails(&policy.guardrails)?;

    // Get current process state for PIDs in plan
    let pids_to_apply: Vec<u32> = /* PIDs from plan or args */;

    // Re-scan target processes to get current state
    let current_state = quick_scan_pids(&pids_to_apply)?;

    // Filter out protected processes
    let filter_result = protected_filter.filter_scan_result(&current_state);

    // Warn about protected processes that were in the plan
    for filtered in &filter_result.filtered {
        warn!(
            pid = filtered.pid,
            pattern = %filtered.pattern,
            "SKIPPING protected process in apply - was in plan but now protected"
        );
    }

    // Only execute actions on non-protected processes
    for proc in &filter_result.passed {
        // Execute action...
    }
}
